// ── BYOK: Client-side Anthropic inference ──

function getApiKey() { return localStorage.getItem("arclight_api_key") || ""; }
function setApiKey(k) { localStorage.setItem("arclight_api_key", k); }
function clearApiKey() { localStorage.removeItem("arclight_api_key"); }

async function runAltTextQuest(imageUrl, context, apiKey) {
  // Download image and convert to base64 in browser
  const imgResp = await fetch(imageUrl);
  const blob = await imgResp.blob();
  const base64 = await new Promise(resolve => {
    const reader = new FileReader();
    reader.onloadend = () => resolve(reader.result.split(",")[1]);
    reader.readAsDataURL(blob);
  });
  const mediaType = blob.type || "image/jpeg";

  const prompt = `You are generating accessibility alt-text for a blind user.

Image context: ${context}

Write a concise, descriptive alt-text for this image. Follow WCAG guidelines:
- Describe the content and function of the image
- Be specific about what's shown (colors, objects, actions, spatial relationships)
- Keep it under 150 words
- Don't start with "Image of" or "Picture of"
- Focus on what a blind user needs to understand the image

Respond with ONLY the alt-text, nothing else.`;

  const resp = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "x-api-key": apiKey,
      "anthropic-version": "2023-06-01",
      "anthropic-dangerous-direct-browser-access": "true",
    },
    body: JSON.stringify({
      model: "claude-sonnet-4-20250514",
      max_tokens: 300,
      messages: [{
        role: "user",
        content: [
          { type: "image", source: { type: "base64", media_type: mediaType, data: base64 } },
          { type: "text", text: prompt }
        ]
      }]
    })
  });

  if (!resp.ok) {
    const err = await resp.json().catch(() => ({}));
    throw new Error(err.error?.message || `API error ${resp.status}`);
  }

  const data = await resp.json();
  const text = data.content[0].text.trim();
  const tokens = data.usage.input_tokens + data.usage.output_tokens;
  const hash = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(text));
  const hashHex = Array.from(new Uint8Array(hash)).map(b => b.toString(16).padStart(2, "0")).join("");

  return { text, tokens_used: tokens, model: "claude-sonnet-4-20250514", hash: hashHex };
}

// ── Shared Components ──

function Petal({ delay, left }) {
  return (
    <div style={{
      position: "absolute", left: left + "%", top: -10,
      width: 5 + Math.random() * 4, height: 5 + Math.random() * 4,
      background: [C.blossom, C.blossomMd, C.blossomLt, C.blossomDk][Math.floor(Math.random()*4)],
      borderRadius: "50% 0 50% 50%", opacity: 0.2 + Math.random() * 0.25,
      animation: `fall ${8 + Math.random()*14}s ${delay}s linear infinite`,
      pointerEvents: "none",
    }} />
  );
}

function Bar({ v, mx, c, h = 6 }) {
  const p = mx > 0 ? Math.min(v/mx*100, 100) : 0;
  return (
    <div style={{ width: "100%", height: h, background: "#ffffff08", borderRadius: h, overflow: "hidden" }}>
      <div style={{ width: p+"%", height: "100%", background: c, borderRadius: h, transition: "width 0.5s" }} />
    </div>
  );
}

function Btn({ children, onClick, primary, disabled, small, style: sx }) {
  return (
    <button disabled={disabled} onClick={onClick} style={{
      fontFamily: M, fontSize: small ? 11 : 13, fontWeight: 600, letterSpacing: 0.3,
      padding: small ? "6px 14px" : "12px 28px", borderRadius: 6, border: "none", cursor: disabled ? "not-allowed" : "pointer",
      opacity: disabled ? 0.4 : 1, transition: "all 0.2s",
      background: primary ? C.blossomDk : "transparent",
      color: primary ? C.blossomLt : C.text2,
      ...(primary ? {} : { border: `1px solid ${C.border}` }),
      ...sx,
    }}>{children}</button>
  );
}

